mapper.select:
SELECT ur.*, cr.role_name
FROM user_role ur
LEFT JOIN app_custom_role cr ON cr.app_code = ur.app_code AND cr.role_code = ur.role_code
WHERE ur.app_code = #{appCode}
  AND ur.user_id = #{userId}
  AND ur.status = 'ENABLED'

SELECT COUNT(1)
FROM user_role
WHERE app_code = #{appCode}
  AND user_id = #{userId}
  AND status = 'ENABLED'
